import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"万剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/万剑.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/万剑.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/白刃类/万剑.md"};function p(d,e,l,i,_,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"万剑",tabindex:"-1"},[n("万剑 "),r("a",{class:"header-anchor",href:"#万剑","aria-label":'Permalink to "万剑"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风026")])])],-1),s('<h1 id="万剑-1" tabindex="-1">万剑 <a class="header-anchor" href="#万剑-1" aria-label="Permalink to &quot;万剑&quot;">​</a></h1><p>【万剑】<br> 剑为何物？<br> 剑为礼器？<br> 剑为君子？<br> 剑为侠客？<br> 剑为？<br> 剑为杀戮之器。<br> 此术法伤人伤己，只求剑，唯求剑。</p><p>【剑心】<br> D+750<br> 明心见性，剑心见己<br> 天心我心，我心剑心<br> 你日夜不休，明神锻心，习得此技艺时，你失去【3】点生命值上限<br> 器随心动，心随神行。<br> 现在你获得将自身神识与剑器共鸣的能力：你可以用神识将至多【决心】属性把剑类武器操控令这些武器在你触及范围内的空间以环形或者扇形的规律排列为剑阵。处于剑阵内的武器不视为你持有，但你可以取用触手可及范围内物品的同等动作将剑阵内的武器进行取用。<br> 你可以用神识驱动手持的剑类武器，在画面上，你可以剑指催用被你神识操控的剑，这依然会占用你相应的手持位，但以此方式使用的剑类武器触及范围增加2米。</p><p>【剑意】<br> C+1000<br> 剑戮我身，剑斩我心<br> 剑断我神，剑如我意<br> 习得此技艺时，你失去【1】点生命值上限<br> 现在，每经过一场影片，你的神识便可以令你额外催动一把剑类武器，被以此方式催动的剑类武器视同手持，在进行攻击时可以将以此方式持有的武器的基础属性的一半与所有特殊效果加入其中，你以此方式获得额外的持有剑类武器数量不会超过你的传奇决心。</p><p>需进行【剑心】【剑意】购买后才可进行以下资源的购买<br> 【剑流】<br> C+1000<br> 剑光流转，剑随我心！<br> 你的武器跟随你行动，当你使用冲锋攻击时，你的武器会令你对移动路径上触及范围内的所有敌方单位造成近战攻击。</p><p>【剑雨】<br> C+1000<br> 剑雨滂沱，银河雨落。<br> 消耗一个标准动作对自身造成1点不可豁免的严重伤害，你对12米范围内的某一个目标进行一次攻击，这次攻击将会命中以目标为圆心，以7.5M为半径的圆形范围内的所有敌人。<br> 接下来，你的攻击将会从天上落下。东风夜放花千树。更吹落，星如雨。</p><p>【剑闪】<br> C+1000<br> 剑光一闪，百刃加身。<br> 你对自己造成1点不可豁免的严重伤害并消耗一个标准动作进行一次攻击，本次攻击将附带B级的重伤效果和d级的措手不及效果，这次攻击可以结合在一次移动中。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
